var wmEnd = "bays:[{n:\"Rossmore Road\"";
var wmEndIdx = c.indexOf(wmEnd);
// Find the closing of the wm zone object
var searchFrom = wmEndIdx;
var depth2 = 0;
var wmCloseIdx = -1;
for (var x = searchFrom; x < c.length; x++) {
  if (c[x] === '{') depth2++;
  if (c[x] === '}') {
    depth2--;
    if (depth2 < 0) { wmCloseIdx = x; break; }
  }
}

// Find the actual end: "}}" that closes the wm zone and ZONES_DATA
// We need to find "}}" after the wm bays array
var zonesEnd = c.indexOf('\n};', wmCloseIdx);
if (zonesEnd === -1) zonesEnd = c.indexOf('};\n', wmCloseIdx);

